$groqPath = "C:\Program Files\Git\usr\bin\groq.exe"

Write-Host "=== Groq 交互终端 ===" -ForegroundColor Cyan
Write-Host "输入消息直接发送，输入 'exit' 或 'quit' 退出" -ForegroundColor Yellow
Write-Host ""

while ($true) {
    $input = Read-Host "Groq"

    if ($input -eq "exit" -or $input -eq "quit") {
        Write-Host "再见！" -ForegroundColor Green
        break
    }

    if ([string]::IsNullOrWhiteSpace($input)) {
        continue
    }

    & $groqPath $input 2>&1 | ForEach-Object {
        $output = $_
        if ($output -is [byte[]]) {
            $output = [System.Text.Encoding]::UTF8.GetString($output)
        }
        Write-Host $output
    }
    Write-Host ""
}

