cat > ~/make-groq-exe.ps1 << 'EOF'
$sourceCode = @"
using System;
using System.Diagnostics;
using System.IO;
using System.Text;
using System.Runtime.InteropServices;

class GroqLauncher
{
    [DllImport("kernel32.dll")]
    static extern bool AllocConsole();

    [DllImport("kernel32.dll")]
    static extern bool SetConsoleTitle(string lpConsoleTitle);

    static void Main()
    {
        AllocConsole();
        SetConsoleTitle("Groq AI Terminal");

        Console.OutputEncoding = Encoding.UTF8;
        Console.InputEncoding = Encoding.UTF8;

        string groqPath = @"C:\Program Files\Git\usr\bin\groq.exe";

        Console.ForegroundColor = ConsoleColor.Cyan;
        Console.WriteLine("=== Groq 交互终端 ===");
        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine("输入消息直接发送，输入 'exit' 或 'quit' 退出");
        Console.ResetColor();
        Console.WriteLine();

        while (true)
        {
            Console.ForegroundColor = ConsoleColor.Green;
            Console.Write("You > ");
            Console.ResetColor();

            string input = Console.ReadLine();

            if (string.IsNullOrWhiteSpace(input))
                continue;

            if (input.Equals("exit", StringComparison.OrdinalIgnoreCase) ||
                input.Equals("quit", StringComparison.OrdinalIgnoreCase))
            {
                Console.ForegroundColor = ConsoleColor.Cyan;
                Console.WriteLine("再见！");
                Console.ResetColor();
                break;
            }

            try
            {
                var proc = new Process
                {
                    StartInfo = new ProcessStartInfo
                    {
                        FileName = groqPath,
                        Arguments = input,
                        UseShellExecute = false,
                        RedirectStandardOutput = true,
                        RedirectStandardError = true,
                        CreateNoWindow = true,
                        StandardOutputEncoding = Encoding.UTF8
                    }
                };

                proc.Start();
                string output = proc.StandardOutput.ReadToEnd();
                string error = proc.StandardError.ReadToEnd();
                proc.WaitForExit();

                Console.ForegroundColor = ConsoleColor.White;
                if (!string.IsNullOrEmpty(output))
                    Console.WriteLine(output);
                if (!string.IsNullOrEmpty(error))
                    Console.WriteLine(error);
                Console.ResetColor();
                Console.WriteLine();
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"错误: {ex.Message}");
                Console.ResetColor();
            }
        }
    }
}
"@

$compilerOptions = @(
    "/target:winexe"
    "/out:C:\Users\Administrator\GroqTerminal.exe"
    "/platform:anycpu"
)

Add-Type -TypeDefinition $sourceCode -Language CSharp -OutputAssembly "C:\Users\Administrator\GroqTerminal.exe" -OutputType ConsoleApplication

Write-Host "已生成: C:\Users\Administrator\GroqTerminal.exe" -ForegroundColor Green
EOF
